ucs.kql:
// EXOTIC LILY — BumbleBee rundll32 invocation from mounted ISO/IMG
// Pattern: rundll32.exe "<DriveLetter>:\<file>.dll",<ExportName>
// where DriveLetter is a removable/virtual mount (D-Z, never C:),
// the parent is explorer.exe (LNK double-click) or cmd.exe (batch),
// and the cmd-line uses the rundll32 "DLL,Export" comma syntax.
let LookbackDays = 14d;
let UserLoaders = dynamic(["rundll32.exe","regsvr32.exe","odbcconf.exe"]);
DeviceProcessEvents
| where Timestamp > ago(LookbackDays)
| where AccountName !endswith "$"
| where FileName in~ (UserLoaders)
// rundll32 with a DLL + comma + export — the BumbleBee invocation shape
| where ProcessCommandLine matches regex @"(?i)[D-Z]:\\[^ ,\"]+\.dll[\"]?\s*,\s*[A-Za-z_][A-Za-z0-9_]{2,40}"
// Exclude Windows-shipped DLLs and signed installers running from C:
| where ProcessCommandLine !contains @"C:\Windows\"
| where ProcessCommandLine !contains @"C:\Program Files"
// Parent is typically explorer (LNK click), cmd, or wscript — NOT msiexec / setup
| where InitiatingProcessFileName in~ ("explorer.exe","cmd.exe","wscript.exe","cscript.exe","powershell.exe","outlook.exe")
| extend MountDrive = extract(@"(?i)([D-Z]):\\", 1, ProcessCommandLine),
         DllPath    = extract(@"(?i)([D-Z]:\\[^ ,\"]+\.dll)", 1, ProcessCommandLine),
         Export     = extract(@"(?i)\.dll[\"]?\s*,\s*([A-Za-z_][A-Za-z0-9_]{2,40})", 1, ProcessCommandLine)
| where isnotempty(MountDrive) and isnotempty(Export)
// Final FP suppression: DLL must NOT be a known signed Windows component
| where Export !in~ ("PrintUIEntry","OpenAs_RunDLL","Control_RunDLL","ShellExec_RunDLL","InstallHinfSection")
| project Timestamp, DeviceName, AccountName,
          Parent = InitiatingProcessFileName,
          ParentCmd = InitiatingProcessCommandLine,
          MountDrive, DllPath, Export,
          ProcessCommandLine, SHA256
| order by Timestamp desc
